const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "mysql",
  "inlineSchema": "// SGA — Sistema de Gestión de Accesos\n// Prisma schema (MySQL 8) — built incrementally per bounded context.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n}\n\n// ─────────────────────────────────────────────\n// Enums\n// ─────────────────────────────────────────────\n\nenum CompanyStatus {\n  ACTIVE\n  INACTIVE\n  SUSPENDED\n}\n\nenum UserStatus {\n  ACTIVE\n  INACTIVE\n  BLOCKED\n}\n\nenum RoleCode {\n  SYSTEM_ADMIN\n  COMPANY_ADMIN\n  APPLICANT\n  DOCUMENT_RECEIVER\n  ACCESS_DOCUMENTS_MANAGER\n  CARD_ISSUER\n}\n\nenum PersonStatus {\n  ACTIVE\n  INACTIVE\n}\n\nenum AuthorizedSignerStatus {\n  ACTIVE\n  INACTIVE\n  REVOKED\n}\n\nenum RequestStatus {\n  DRAFT\n  SUBMITTED\n  UNDER_DOCUMENT_REVIEW\n  RETURNED_FOR_CORRECTION\n  DOCUMENTS_APPROVED\n  PENDING_FINAL_APPROVAL\n  APPROVED\n  REJECTED\n  IN_PRODUCTION\n  READY_FOR_DELIVERY\n  DELIVERED\n  CANCELLED\n}\n\nenum RequestType {\n  PERMANENT_CARD\n  TEMPORARY_PERSON\n  TEMPORARY_VEHICLE\n  TEMPORARY_EQUIPMENT\n}\n\nenum RequestPersonRole {\n  PRIMARY\n  BENEFICIARY\n}\n\nenum ReviewStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum TaskType {\n  DOCUMENT_REVIEW\n  FINAL_APPROVAL\n}\n\nenum TaskStatus {\n  PENDING\n  ASSIGNED\n  COMPLETED\n  CANCELLED\n}\n\nenum CatalogKind {\n  REQUEST_TYPE\n  IDENTIFICATION_TYPE\n  DOCUMENT_TYPE\n  ACCESS_POINT\n  SECURITY_ZONE\n  ACCESS_AREA\n  REJECTION_REASON\n  GENDER\n  MARITAL_STATUS\n  BLOOD_TYPE\n  NATIONALITY\n}\n\nenum DocumentStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  REPLACED\n}\n\nenum DocumentSubjectType {\n  REQUEST\n  PERSON\n}\n\nenum CredentialType {\n  PERMANENT_CARD\n  TEMPORARY_PERSON_PASS\n  TEMPORARY_VEHICLE_PASS\n  TEMPORARY_EQUIPMENT_PASS\n}\n\nenum CredentialStatus {\n  PENDING_PRODUCTION\n  IN_PRODUCTION\n  READY_FOR_DELIVERY\n  DELIVERED\n  SUSPENDED\n  REVOKED\n  EXPIRED\n  CANCELLED\n}\n\nenum EventType {\n  CREATED\n  SUBMITTED\n  RESUBMITTED\n  ASSIGNED\n  DOCUMENT_APPROVED\n  DOCUMENT_REJECTED\n  STAGE_APPROVED\n  RETURNED\n  REJECTED\n  APPROVED\n  STARTED_PRODUCTION\n  MARKED_READY\n  DELIVERED\n  REVERTED_PRODUCTION\n  RETURNED_TO_PRODUCTION\n  CORRECTED_DELIVERY\n  CANCELLED\n  REVOKED_SIGNER\n  DEACTIVATED\n  SUSPENDED\n  ACTIVATED\n}\n\n// ─────────────────────────────────────────────\n// 1. ORGANIZATIONS\n// ─────────────────────────────────────────────\n\nmodel Company {\n  id              String        @id @default(uuid())\n  legalName       String        @map(\"legal_name\") @db.VarChar(255)\n  tradeName       String?       @map(\"trade_name\") @db.VarChar(255)\n  taxIdentifier   String?       @unique @map(\"tax_identifier\") @db.VarChar(50)\n  email           String?       @db.VarChar(255)\n  phone           String?       @db.VarChar(50)\n  address         String?       @db.Text\n  logoUrl         String?       @map(\"logo_url\") @db.VarChar(512)\n  mainContactName String?       @map(\"main_contact_name\") @db.VarChar(255)\n  status          CompanyStatus @default(ACTIVE)\n  createdAt       DateTime      @default(now()) @map(\"created_at\")\n  updatedAt       DateTime      @updatedAt @map(\"updated_at\")\n\n  users             User[]\n  people            Person[]\n  authorizedSigners CompanyAuthorizedSigner[]\n  requests          Request[]\n\n  @@map(\"companies\")\n}\n\n// ─────────────────────────────────────────────\n// 2. IDENTITY AND ACCESS\n// ─────────────────────────────────────────────\n\nmodel Role {\n  id          String   @id @default(uuid())\n  code        RoleCode @unique\n  name        String   @db.VarChar(100)\n  description String?  @db.Text\n  isSystem    Boolean  @default(false) @map(\"is_system\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  rolesPermissions RolePermission[]\n  users            UserRole[]\n\n  @@map(\"roles\")\n}\n\nmodel Permission {\n  id          String   @id @default(uuid())\n  code        String   @unique @db.VarChar(100)\n  name        String   @db.VarChar(200)\n  description String?  @db.Text\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  rolesPermissions RolePermission[]\n\n  @@map(\"permissions\")\n}\n\nmodel RolePermission {\n  roleId       String   @map(\"role_id\")\n  permissionId String   @map(\"permission_id\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  role       Role       @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  permission Permission @relation(fields: [permissionId], references: [id], onDelete: Cascade)\n\n  @@unique([roleId, permissionId])\n  @@map(\"role_permissions\")\n}\n\nmodel User {\n  id           String     @id @default(uuid())\n  companyId    String?    @map(\"company_id\")\n  firstName    String     @map(\"first_name\") @db.VarChar(100)\n  lastName     String     @map(\"last_name\") @db.VarChar(100)\n  email        String     @unique @db.VarChar(255)\n  passwordHash String     @map(\"password_hash\") @db.VarChar(255)\n  status       UserStatus @default(ACTIVE)\n  lastAccessAt DateTime?  @map(\"last_access_at\")\n  createdBy    String?    @map(\"created_by\") @db.VarChar(36)\n  createdAt    DateTime   @default(now()) @map(\"created_at\")\n  updatedAt    DateTime   @updatedAt @map(\"updated_at\")\n\n  company         Company?         @relation(fields: [companyId], references: [id], onDelete: SetNull)\n  userRoles       UserRole[]\n  refreshSessions RefreshSession[]\n  createdRequests Request[]        @relation(\"RequestCreator\")\n  notifications   Notification[]\n\n  @@index([companyId])\n  @@map(\"users\")\n}\n\nmodel UserRole {\n  userId    String   @map(\"user_id\")\n  roleId    String   @map(\"role_id\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role Role @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, roleId])\n  @@map(\"user_roles\")\n}\n\nmodel RefreshSession {\n  id        String    @id @default(uuid())\n  userId    String    @map(\"user_id\")\n  tokenHash String    @unique @map(\"token_hash\") @db.VarChar(255)\n  userAgent String?   @map(\"user_agent\") @db.Text\n  ipAddress String?   @map(\"ip_address\") @db.VarChar(45)\n  expiresAt DateTime  @map(\"expires_at\")\n  revokedAt DateTime? @map(\"revoked_at\")\n  createdAt DateTime  @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"refresh_sessions\")\n}\n\n// ─────────────────────────────────────────────\n// 3. PEOPLE AND AUTHORIZED SIGNERS\n// ─────────────────────────────────────────────\n\nmodel Person {\n  id                        String       @id @default(uuid())\n  companyId                 String       @map(\"company_id\")\n  firstName                 String       @map(\"first_name\") @db.VarChar(100)\n  middleName                String?      @map(\"middle_name\") @db.VarChar(100)\n  firstSurname              String       @map(\"first_surname\") @db.VarChar(100)\n  secondSurname             String?      @map(\"second_surname\") @db.VarChar(100)\n  marriedSurname            String?      @map(\"married_surname\") @db.VarChar(100)\n  identificationTypeId      String       @map(\"identification_type_id\")\n  identificationNumber      String       @map(\"identification_number\") @db.VarChar(50)\n  socialSecurityNumber      String?      @map(\"social_security_number\") @db.VarChar(50)\n  birthDate                 DateTime?    @map(\"birth_date\")\n  gender                    String?      @db.VarChar(20)\n  maritalStatus             String?      @map(\"marital_status\") @db.VarChar(30)\n  nationality               String?      @db.VarChar(80)\n  bloodType                 String?      @map(\"blood_type\") @db.VarChar(5)\n  phone                     String?      @db.VarChar(50)\n  mobile                    String?      @db.VarChar(50)\n  email                     String?      @db.VarChar(255)\n  residentialAddress        String?      @map(\"residential_address\") @db.Text\n  physicalCondition         String?      @map(\"physical_condition\") @db.VarChar(255)\n  department                String?      @db.VarChar(120)\n  position                  String?      @db.VarChar(120)\n  yearsOfService            Int?         @map(\"years_of_service\")\n  previouslyWorkedAtAirport Boolean      @default(false) @map(\"previously_worked_at_airport\")\n  previousCompanyName       String?      @map(\"previous_company_name\") @db.VarChar(255)\n  previouslyHadCredential   Boolean      @default(false) @map(\"previously_had_credential\")\n  reusePreviousPhoto        Boolean      @default(false) @map(\"reuse_previous_photo\")\n  status                    PersonStatus @default(ACTIVE)\n  createdBy                 String?      @map(\"created_by\") @db.VarChar(36)\n  createdAt                 DateTime     @default(now()) @map(\"created_at\")\n  updatedAt                 DateTime     @updatedAt @map(\"updated_at\")\n\n  company            Company                   @relation(fields: [companyId], references: [id], onDelete: Restrict)\n  identificationType CatalogItem               @relation(\"PersonIdentificationType\", fields: [identificationTypeId], references: [id], onDelete: Restrict)\n  authorizedSigners  CompanyAuthorizedSigner[]\n  requestPeople      RequestPerson[]\n\n  @@unique([identificationTypeId, identificationNumber])\n  @@index([companyId])\n  @@index([firstName, firstSurname])\n  @@index([status])\n  @@map(\"people\")\n}\n\nmodel CompanyAuthorizedSigner {\n  id                      String                 @id @default(uuid())\n  companyId               String                 @map(\"company_id\")\n  personId                String                 @map(\"person_id\")\n  position                String                 @db.VarChar(120)\n  validFrom               DateTime               @map(\"valid_from\")\n  validUntil              DateTime?              @map(\"valid_until\")\n  authorizationDocumentId String?                @map(\"authorization_document_id\") @db.VarChar(36)\n  signatureFileId         String?                @map(\"signature_file_id\") @db.VarChar(36)\n  status                  AuthorizedSignerStatus @default(ACTIVE)\n  revokedAt               DateTime?              @map(\"revoked_at\")\n  revokedBy               String?                @map(\"revoked_by\") @db.VarChar(36)\n  revocationReason        String?                @map(\"revocation_reason\") @db.Text\n  createdAt               DateTime               @default(now()) @map(\"created_at\")\n  updatedAt               DateTime               @updatedAt @map(\"updated_at\")\n\n  company  Company   @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  person   Person    @relation(fields: [personId], references: [id], onDelete: Restrict)\n  requests Request[]\n\n  @@index([companyId])\n  @@index([personId])\n  @@index([status])\n  @@map(\"company_authorized_signers\")\n}\n\n// ─────────────────────────────────────────────\n// 4. CATALOGS (single source of truth)\n// ─────────────────────────────────────────────\n\nmodel CatalogItem {\n  id             String      @id @default(uuid())\n  kind           CatalogKind\n  code           String      @db.VarChar(80)\n  name           String      @db.VarChar(200)\n  description    String?     @db.Text\n  isActive       Boolean     @default(true) @map(\"is_active\")\n  displayOrder   Int         @default(0) @map(\"display_order\")\n  parentZoneCode String?     @map(\"parent_zone_code\") @db.VarChar(40)\n  metadata       Json?\n  createdAt      DateTime    @default(now()) @map(\"created_at\")\n  updatedAt      DateTime    @updatedAt @map(\"updated_at\")\n\n  identificationTypePeople Person[]              @relation(\"PersonIdentificationType\")\n  requestTypeRequests      Request[]             @relation(\"RequestType\")\n  accessPointRequests      RequestAccessPoint[]\n  accessAreaRequests       RequestAccessArea[]\n  documentRequestDocuments RequestDocument[]\n  documentRequirementTypes DocumentRequirement[] @relation(\"DocumentRequirementRequestType\")\n  documentRequirementDocs  DocumentRequirement[] @relation(\"DocumentRequirementDocumentType\")\n  rejectionReasonRequests  Request[]             @relation(\"RequestRejectionReason\")\n\n  @@unique([kind, code])\n  @@index([kind, isActive, displayOrder])\n  @@map(\"catalog_items\")\n}\n\n// ─────────────────────────────────────────────\n// 5. ACCESS REQUESTS (root aggregate)\n// ─────────────────────────────────────────────\n\nmodel Request {\n  id                 String        @id @default(uuid())\n  requestNumber      String?       @unique @map(\"request_number\") @db.VarChar(30)\n  companyId          String        @map(\"company_id\")\n  requestTypeId      String        @map(\"request_type_id\")\n  createdByUserId    String        @map(\"created_by_user_id\")\n  createdByCompanyId String?       @map(\"created_by_company_id\")\n  authorizedSignerId String?       @map(\"authorized_signer_id\")\n  rejectionReasonId  String?       @map(\"rejection_reason_id\")\n  reason             String        @db.Text\n  serviceCompanyName String?       @map(\"service_company_name\") @db.VarChar(255)\n  validFrom          DateTime?     @map(\"valid_from\")\n  validUntil         DateTime?     @map(\"valid_until\")\n  scheduleFrom       String?       @map(\"schedule_from\") @db.VarChar(10)\n  scheduleUntil      String?       @map(\"schedule_until\") @db.VarChar(10)\n  observations       String?       @db.Text\n  status             RequestStatus @default(DRAFT)\n  version            Int           @default(1)\n  submittedAt        DateTime?     @map(\"submitted_at\")\n  cancelledAt        DateTime?     @map(\"cancelled_at\")\n  createdAt          DateTime      @default(now()) @map(\"created_at\")\n  updatedAt          DateTime      @updatedAt @map(\"updated_at\")\n\n  company          Company                  @relation(fields: [companyId], references: [id], onDelete: Restrict)\n  requestType      CatalogItem              @relation(\"RequestType\", fields: [requestTypeId], references: [id], onDelete: Restrict)\n  createdByUser    User                     @relation(\"RequestCreator\", fields: [createdByUserId], references: [id], onDelete: Restrict)\n  authorizedSigner CompanyAuthorizedSigner? @relation(fields: [authorizedSignerId], references: [id], onDelete: SetNull)\n  rejectionReason  CatalogItem?             @relation(\"RequestRejectionReason\", fields: [rejectionReasonId], references: [id], onDelete: SetNull)\n  personLinks      RequestPerson[]\n  vehicles         RequestVehicle[]\n  equipment        RequestEquipment[]\n  accessPoints     RequestAccessPoint[]\n  accessAreas      RequestAccessArea[]\n  documents        RequestDocument[]\n  submissions      RequestSubmission[]\n  events           RequestEvent[]\n  reviewTasks      ReviewTask[]\n  credential       Credential?\n\n  @@index([companyId])\n  @@index([status])\n  @@index([requestTypeId])\n  @@index([createdByUserId])\n  @@index([createdAt])\n  @@map(\"requests\")\n}\n\nmodel RequestPerson {\n  id                     String            @id @default(uuid())\n  requestId              String            @map(\"request_id\")\n  personId               String            @map(\"person_id\")\n  role                   RequestPersonRole\n  personalEmergency      Boolean           @default(false) @map(\"personal_emergency\")\n  usePreviousPhoto       Boolean           @default(false) @map(\"use_previous_photo\")\n  departmentSnapshot     String?           @map(\"department_snapshot\") @db.VarChar(120)\n  positionSnapshot       String?           @map(\"position_snapshot\") @db.VarChar(120)\n  companyNameSnapshot    String?           @map(\"company_name_snapshot\") @db.VarChar(255)\n  identificationSnapshot String?           @map(\"identification_snapshot\") @db.VarChar(120)\n  fullNameSnapshot       String?           @map(\"full_name_snapshot\") @db.VarChar(255)\n  createdAt              DateTime          @default(now()) @map(\"created_at\")\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n  person  Person  @relation(fields: [personId], references: [id], onDelete: Restrict)\n\n  @@unique([requestId, personId])\n  @@index([requestId])\n  @@map(\"request_persons\")\n}\n\nmodel RequestVehicle {\n  id          String   @id @default(uuid())\n  requestId   String   @map(\"request_id\")\n  brand       String   @db.VarChar(120)\n  model       String   @db.VarChar(120)\n  plateNumber String   @map(\"plate_number\") @db.VarChar(50)\n  color       String?  @db.VarChar(50)\n  year        Int?\n  description String?  @db.Text\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  @@unique([requestId, plateNumber])\n  @@index([requestId])\n  @@map(\"request_vehicles\")\n}\n\nmodel RequestEquipment {\n  id            String   @id @default(uuid())\n  requestId     String   @map(\"request_id\")\n  brand         String?  @db.VarChar(120)\n  equipmentType String   @map(\"equipment_type\") @db.VarChar(120)\n  serialNumber  String?  @map(\"serial_number\") @db.VarChar(100)\n  description   String?  @db.Text\n  quantity      Int      @default(1)\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  @@unique([requestId, serialNumber])\n  @@index([requestId])\n  @@map(\"request_equipment\")\n}\n\nmodel RequestAccessPoint {\n  id            String   @id @default(uuid())\n  requestId     String   @map(\"request_id\")\n  accessPointId String   @map(\"access_point_id\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  request     Request     @relation(fields: [requestId], references: [id], onDelete: Cascade)\n  accessPoint CatalogItem @relation(fields: [accessPointId], references: [id], onDelete: Restrict)\n\n  @@unique([requestId, accessPointId])\n  @@index([requestId])\n  @@map(\"request_access_points\")\n}\n\nmodel RequestAccessArea {\n  id            String       @id @default(uuid())\n  requestId     String       @map(\"request_id\")\n  accessAreaId  String       @map(\"access_area_id\")\n  justification String?      @db.Text\n  reviewStatus  ReviewStatus @default(PENDING) @map(\"review_status\")\n  reviewedBy    String?      @map(\"reviewed_by\") @db.VarChar(36)\n  reviewedAt    DateTime?    @map(\"reviewed_at\")\n  reviewComment String?      @map(\"review_comment\") @db.Text\n  createdAt     DateTime     @default(now()) @map(\"created_at\")\n\n  request    Request     @relation(fields: [requestId], references: [id], onDelete: Cascade)\n  accessArea CatalogItem @relation(fields: [accessAreaId], references: [id], onDelete: Restrict)\n\n  @@unique([requestId, accessAreaId])\n  @@index([requestId])\n  @@index([reviewStatus])\n  @@map(\"request_access_areas\")\n}\n\n// ─────────────────────────────────────────────\n// 6. DOCUMENTS AND DOCUMENT VERSIONS\n// ─────────────────────────────────────────────\n\nmodel RequestDocument {\n  id               String              @id @default(uuid())\n  requestId        String              @map(\"request_id\")\n  documentTypeId   String              @map(\"document_type_id\")\n  subjectType      DocumentSubjectType @map(\"subject_type\")\n  subjectId        String?             @map(\"subject_id\") @db.VarChar(36)\n  currentVersionId String?             @map(\"current_version_id\") @db.VarChar(36)\n  status           DocumentStatus      @default(PENDING)\n  createdAt        DateTime            @default(now()) @map(\"created_at\")\n  updatedAt        DateTime            @updatedAt @map(\"updated_at\")\n\n  request      Request           @relation(fields: [requestId], references: [id], onDelete: Cascade)\n  documentType CatalogItem       @relation(fields: [documentTypeId], references: [id], onDelete: Restrict)\n  versions     DocumentVersion[]\n  reviews      DocumentReview[]\n\n  @@index([requestId])\n  @@index([status])\n  @@map(\"request_documents\")\n}\n\nmodel DocumentVersion {\n  id                String   @id @default(uuid())\n  requestDocumentId String   @map(\"request_document_id\")\n  versionNumber     Int      @map(\"version_number\")\n  originalFilename  String   @map(\"original_filename\") @db.VarChar(255)\n  storedFilename    String   @map(\"stored_filename\") @db.VarChar(255)\n  storageKey        String   @map(\"storage_key\") @db.VarChar(512)\n  mimeType          String   @map(\"mime_type\") @db.VarChar(100)\n  size              BigInt\n  sha256            String   @db.VarChar(64)\n  uploadedBy        String   @map(\"uploaded_by\") @db.VarChar(36)\n  uploadedAt        DateTime @default(now()) @map(\"uploaded_at\")\n\n  requestDocument RequestDocument  @relation(fields: [requestDocumentId], references: [id], onDelete: Cascade)\n  reviews         DocumentReview[]\n\n  @@unique([requestDocumentId, versionNumber])\n  @@index([requestDocumentId])\n  @@index([sha256])\n  @@map(\"document_versions\")\n}\n\nmodel DocumentReview {\n  id                String       @id @default(uuid())\n  requestDocumentId String       @map(\"request_document_id\")\n  documentVersionId String       @map(\"document_version_id\")\n  decision          ReviewStatus\n  comment           String?      @db.Text\n  reviewedBy        String       @map(\"reviewed_by\") @db.VarChar(36)\n  reviewedAt        DateTime     @default(now()) @map(\"reviewed_at\")\n\n  requestDocument RequestDocument @relation(fields: [requestDocumentId], references: [id], onDelete: Cascade)\n  documentVersion DocumentVersion @relation(fields: [documentVersionId], references: [id], onDelete: Cascade)\n\n  @@index([requestDocumentId])\n  @@index([documentVersionId])\n  @@map(\"document_reviews\")\n}\n\nmodel DocumentRequirement {\n  id             String              @id @default(uuid())\n  requestTypeId  String              @map(\"request_type_id\")\n  documentTypeId String              @map(\"document_type_id\")\n  subjectType    DocumentSubjectType @map(\"subject_type\")\n  isRequired     Boolean             @default(true) @map(\"is_required\")\n  minFiles       Int                 @default(1) @map(\"min_files\")\n  maxFiles       Int                 @default(10) @map(\"max_files\")\n  isActive       Boolean             @default(true) @map(\"is_active\")\n  createdAt      DateTime            @default(now()) @map(\"created_at\")\n  updatedAt      DateTime            @updatedAt @map(\"updated_at\")\n\n  requestType  CatalogItem @relation(\"DocumentRequirementRequestType\", fields: [requestTypeId], references: [id], onDelete: Cascade)\n  documentType CatalogItem @relation(\"DocumentRequirementDocumentType\", fields: [documentTypeId], references: [id], onDelete: Cascade)\n\n  @@unique([requestTypeId, documentTypeId, subjectType])\n  @@index([requestTypeId])\n  @@map(\"document_requirements\")\n}\n\nmodel FileMetadata {\n  id               String   @id @default(uuid())\n  storageKey       String   @unique @map(\"storage_key\") @db.VarChar(512)\n  originalFilename String   @map(\"original_filename\") @db.VarChar(255)\n  storedFilename   String   @map(\"stored_filename\") @db.VarChar(255)\n  mimeType         String   @map(\"mime_type\") @db.VarChar(100)\n  size             BigInt\n  sha256           String   @db.VarChar(64)\n  createdAt        DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"file_metadata\")\n}\n\n// ─────────────────────────────────────────────\n// 7. SUBMISSION SNAPSHOTS\n// ─────────────────────────────────────────────\n\nmodel RequestSubmission {\n  id                   String   @id @default(uuid())\n  requestId            String   @map(\"request_id\")\n  sequence             Int\n  submittedBy          String   @map(\"submitted_by\") @db.VarChar(36)\n  submittedAt          DateTime @default(now()) @map(\"submitted_at\")\n  snapshotJson         Json     @map(\"snapshot_json\")\n  snapshotHash         String   @map(\"snapshot_hash\") @db.VarChar(64)\n  previousSubmissionId String?  @map(\"previous_submission_id\") @db.VarChar(36)\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  @@unique([requestId, sequence])\n  @@index([requestId])\n  @@map(\"request_submissions\")\n}\n\n// ─────────────────────────────────────────────\n// 8. WORKFLOW: EVENTS AND REVIEW TASKS\n// ─────────────────────────────────────────────\n\nmodel RequestEvent {\n  id             String         @id @default(uuid())\n  requestId      String         @map(\"request_id\")\n  eventType      EventType      @map(\"event_type\")\n  fromStatus     RequestStatus? @map(\"from_status\")\n  toStatus       RequestStatus  @map(\"to_status\")\n  actorUserId    String?        @map(\"actor_user_id\") @db.VarChar(36)\n  actorRoleCode  String?        @map(\"actor_role_code\") @db.VarChar(60)\n  actorCompanyId String?        @map(\"actor_company_id\") @db.VarChar(36)\n  reasonCode     String?        @map(\"reason_code\") @db.VarChar(80)\n  comment        String?        @db.Text\n  metadata       Json?\n  ipAddress      String?        @map(\"ip_address\") @db.VarChar(45)\n  userAgent      String?        @map(\"user_agent\") @db.Text\n  correlationId  String?        @map(\"correlation_id\") @db.VarChar(36)\n  occurredAt     DateTime       @default(now()) @map(\"occurred_at\")\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  @@index([requestId, occurredAt])\n  @@index([actorUserId])\n  @@index([eventType])\n  @@map(\"request_events\")\n}\n\nmodel ReviewTask {\n  id               String     @id @default(uuid())\n  requestId        String     @map(\"request_id\")\n  taskType         TaskType   @map(\"task_type\")\n  status           TaskStatus @default(PENDING)\n  assignedToUserId String?    @map(\"assigned_to_user_id\") @db.VarChar(36)\n  assignedRoleCode String?    @map(\"assigned_role_code\") @db.VarChar(60)\n  createdAt        DateTime   @default(now()) @map(\"created_at\")\n  assignedAt       DateTime?  @map(\"assigned_at\")\n  completedAt      DateTime?  @map(\"completed_at\")\n  dueAt            DateTime?  @map(\"due_at\")\n\n  request Request @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  @@index([requestId])\n  @@index([status])\n  @@index([assignedToUserId])\n  @@map(\"review_tasks\")\n}\n\n// ─────────────────────────────────────────────\n// 9. CREDENTIAL ISSUANCE\n// ─────────────────────────────────────────────\n\nmodel Credential {\n  id               String           @id @default(uuid())\n  credentialNumber String           @unique @map(\"credential_number\") @db.VarChar(30)\n  requestId        String           @unique @map(\"request_id\")\n  credentialType   CredentialType   @map(\"credential_type\")\n  personId         String?          @map(\"person_id\") @db.VarChar(36)\n  status           CredentialStatus @default(PENDING_PRODUCTION)\n  issuedAt         DateTime?        @map(\"issued_at\")\n  expiresAt        DateTime?        @map(\"expires_at\")\n  producedAt       DateTime?        @map(\"produced_at\")\n  readyAt          DateTime?        @map(\"ready_at\")\n  deliveredAt      DateTime?        @map(\"delivered_at\")\n  createdBy        String           @map(\"created_by\") @db.VarChar(36)\n  createdAt        DateTime         @default(now()) @map(\"created_at\")\n  updatedAt        DateTime         @updatedAt @map(\"updated_at\")\n\n  request        Request           @relation(fields: [requestId], references: [id], onDelete: Restrict)\n  events         CredentialEvent[]\n  deliveryRecord DeliveryRecord?\n\n  @@index([status])\n  @@index([credentialType])\n  @@map(\"credentials\")\n}\n\nmodel CredentialEvent {\n  id           String            @id @default(uuid())\n  credentialId String            @map(\"credential_id\")\n  eventType    EventType         @map(\"event_type\")\n  fromStatus   CredentialStatus? @map(\"from_status\")\n  toStatus     CredentialStatus  @map(\"to_status\")\n  actorUserId  String?           @map(\"actor_user_id\") @db.VarChar(36)\n  comment      String?           @db.Text\n  occurredAt   DateTime          @default(now()) @map(\"occurred_at\")\n\n  credential Credential @relation(fields: [credentialId], references: [id], onDelete: Cascade)\n\n  @@index([credentialId, occurredAt])\n  @@map(\"credential_events\")\n}\n\nmodel DeliveryRecord {\n  id                       String    @id @default(uuid())\n  credentialId             String    @unique @map(\"credential_id\")\n  deliveredByUserId        String    @map(\"delivered_by_user_id\") @db.VarChar(36)\n  receivedByName           String    @map(\"received_by_name\") @db.VarChar(120)\n  receivedByIdentification String    @map(\"received_by_identification\") @db.VarChar(80)\n  deliveredAt              DateTime  @map(\"delivered_at\")\n  observations             String?   @db.Text\n  correctedAt              DateTime? @map(\"corrected_at\")\n  correctionReason         String?   @map(\"correction_reason\") @db.Text\n\n  credential Credential @relation(fields: [credentialId], references: [id], onDelete: Cascade)\n\n  @@map(\"delivery_records\")\n}\n\n// ─────────────────────────────────────────────\n// 10. NOTIFICATIONS\n// ─────────────────────────────────────────────\n\nmodel Notification {\n  id         String    @id @default(uuid())\n  userId     String    @map(\"user_id\") @db.VarChar(36)\n  type       String    @db.VarChar(80)\n  title      String    @db.VarChar(255)\n  message    String    @db.Text\n  entityType String?   @map(\"entity_type\") @db.VarChar(60)\n  entityId   String?   @map(\"entity_id\") @db.VarChar(36)\n  readAt     DateTime? @map(\"read_at\")\n  createdAt  DateTime  @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, readAt])\n  @@map(\"notifications\")\n}\n\n// ─────────────────────────────────────────────\n// 11. AUDIT (immutable log)\n// ─────────────────────────────────────────────\n\nmodel AuditEvent {\n  id             String   @id @default(uuid())\n  actorUserId    String?  @map(\"actor_user_id\") @db.VarChar(36)\n  actorCompanyId String?  @map(\"actor_company_id\") @db.VarChar(36)\n  action         String   @db.VarChar(100)\n  aggregateType  String   @map(\"aggregate_type\") @db.VarChar(60)\n  aggregateId    String?  @map(\"aggregate_id\") @db.VarChar(36)\n  previousData   Json?    @map(\"previous_data\")\n  newData        Json?    @map(\"new_data\")\n  metadata       Json?\n  ipAddress      String?  @map(\"ip_address\") @db.VarChar(45)\n  userAgent      String?  @map(\"user_agent\") @db.Text\n  correlationId  String?  @map(\"correlation_id\") @db.VarChar(36)\n  occurredAt     DateTime @default(now()) @map(\"occurred_at\")\n\n  @@index([aggregateType, aggregateId])\n  @@index([actorUserId])\n  @@index([action, occurredAt])\n  @@index([occurredAt])\n  @@map(\"audit_events\")\n}\n\n// ─────────────────────────────────────────────\n// 12. IDEMPOTENCY (dedupe for repeated HTTP calls)\n// ─────────────────────────────────────────────\n\nmodel IdempotencyRecord {\n  id           String   @id @default(uuid())\n  key          String   @unique @db.VarChar(120)\n  actorUserId  String?  @map(\"actor_user_id\") @db.VarChar(36)\n  requestPath  String   @map(\"request_path\") @db.VarChar(255)\n  statusCode   Int      @map(\"status_code\")\n  responseBody Json?    @map(\"response_body\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  expiresAt    DateTime @map(\"expires_at\")\n\n  @@index([actorUserId])\n  @@index([expiresAt])\n  @@map(\"idempotency_records\")\n}\n"
}

